//                                                                                 ||//                         بِسْمِ ٱللّٰهِ ٱلرَّحْمٰنِ ٱلرَّحِيمِ                                       ||// "وَلَقَدْ خَلَقْنَا الْإِنْسَانَ وَنَعْلَمُ مَا تُوَسْوِسُ بِهِ نَفْسُهُ ۖ وَنَحْنُ أَقْرَبُ إِلَيْهِ مِنْ حَبْلِ الْوَرِيدِ" (Quran 50:16) -     ||//                                                                                 ||#include<bits/stdc++.h>using namespace std; int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        int n;        cin>>n;        string a,b;        cin>>a>>b;        vector<int> dp(n+1, n+1);        dp[0]= 0;        for(int i=1;i<=n;i++){            dp[i]=min(dp[i], dp[i-1]+(a[i-1]!=b[i-1]));            if(i>=2){                int cost=(a[i-2]!=a[i-1])+(b[i-2]!=b[i-1]);                dp[i]=min(dp[i], dp[i-2]+cost);            }        }        cout<<dp[n]<<"\n";    }}